'use strict';
({params, imports}) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const condition11 = new imports.rulesConfig.RuleCondition({encounter, formElement}).when.valueInEncounter("fbe9a2fe-2bd3-22da-d45d-c3c411ea2e57").containsAnswerConceptName("dde76252-3032-41f5-ab53-1802951574ee").matches();

  visibility = condition11 ;

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

'use strict';
({params, imports}) => {
  const statusBuilder = new imports.rulesConfig.FormElementStatusBuilder({entity: params.entity, formElement: params.formElement});
  statusBuilder.show();
  const userName = params.user ? params.user.name : null;
  if (userName) {
    return new imports.rulesConfig.FormElementStatus(params.formElement.uuid, true, userName);
  }
  return statusBuilder.build();
};

'use strict';
({params, imports}) => {
  const entity = params.entity;
  const formElement = params.formElement;
  const db = params.db;
  if (!db) return new imports.rulesConfig.FormElementStatus(formElement.uuid, true, null);
  const activityUuid = entity.individual.uuid;
  const allParticipants = db.objects('Individual').filtered('voided = false AND subjectType.name = "Participant"');
  let count = 0;
  for (let i = 0; i < allParticipants.length; i++) {
    const p = allParticipants[i];
    if (!(p.gender && p.gender.name === 'Male')) continue;
    const encs = p.nonVoidedEncounters().filter(e => e.encounterType.name === 'Assessment & Distribution');
    if (encs.some(e => { const ref = e.getObservationValue('Activity'); return ref && ref.uuid === activityUuid; })) count++;
  }
  return new imports.rulesConfig.FormElementStatus(formElement.uuid, true, count);
};

