validationRule:
'use strict';
({params, imports}) => {
  const entity = params.entity;
  const validationResults = [];
  const contactCR = entity.getObservationValue('Contact number of CR');
  if (contactCR) {
    const s = String(Math.round(contactCR));
    if (s.length !== 10 || !/^[6-9]/.test(s)) {
      validationResults.push(imports.common.createValidationError('Contact number of CR must be 10 digits starting with 6-9'));
    }
  }
  return validationResults;
};
